module ssdec(in, enable, out);
    //Setup IO
    input wire [3:0]in, enable;
    output wire [6:0]out;
    //Declare Array
    wire [15:0] aarray;
    wire [15:0] barray;
    wire [15:0] carray;
    wire [15:0] darray;
    wire [15:0] earray;
    wire [15:0] farray;
    wire [15:0] garray;
    
    //Declare Inputs
    wire W;
    wire X;
    wire Y;
    wire Z;
    
    //Truth Tables
    assign aarray[15:0] = {1'b1,1'b1,1'b0,1'b1,1'b0,1'b1,1'b1,1'b1,1'b1,1'b1,1'b1,1'b0,1'b1,1'b1,1'b0,1'b1};
