    //Input Assignment
    assign W = in[3];
    assign X = in[2];
    assign Y = in[1];
    assign Z = in[0];
    //7 Segments Outputs
    assign out[0] = aarray[{W,X,Y,Z}] & enable;
    assign out[1] = barray[{W,X,Y,Z}] & enable;
    assign out[2] = carray[{W,X,Y,Z}] & enable;
